          "tio", "elva", "tolv", "tretton", "fjorton", "femton", "sexton", "sjutton",
          "arton", "nitton"];

     private static readonly string[] TensMap =
         ["", "tio", "tjugo", "trettio", "fyrtio", "femtio", "sextio", "sjuttio", "åttio", "nittio"];

     private static readonly FrozenDictionary<long, string> OrdinalExceptions = new Dictionary<long, string>
     {
         { 1, "första" },
         { 2, "andra" },
         { 3, "tredje" },
