             return $"minus {Convert(-number)}";
         }

         var word = "";

         if (number / 1_000_000_000 > 0)
         {
             word += Convert(number / 1_000_000_000) + " miljarder ";
             number %= 1_000_000_000;
         }

         if (number / 1_000_000 > 0)
         {
             word += Convert(number / 1_000_000) + " miljoner ";
             number %= 1_000_000;
         }

